# Shapes module with concrete shape implementations

from types import Color, Point, IDrawable, IScalable, Shape

class Circle(Shape, IDrawable, IScalable):
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float, color: Color):
        super().__init__(color)
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius ** 2.0

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return "Circle at (" + str(self.center.x) + ", " + str(self.center.y) + ")"

    @override
    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

class Rectangle(Shape, IDrawable):
    width: float
    height: float
    top_left: Point

    def __init__(self, top_left: Point, width: float, height: float, color: Color):
        super().__init__(color)
        self.top_left = top_left
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return "Rectangle at (" + str(self.top_left.x) + ", " + str(self.top_left.y) + ")"

class Triangle(Shape, IDrawable, IScalable):
    p1: Point
    p2: Point
    p3: Point

    def __init__(self, p1: Point, p2: Point, p3: Point, color: Color):
        super().__init__(color)
        self.p1 = p1
        self.p2 = p2
        self.p3 = p3

    @override
    def area(self) -> float:
        # Using Heron's formula
        a: float = ((self.p1.x - self.p2.x) ** 2.0 + (self.p1.y - self.p2.y) ** 2.0) ** 0.5
        b: float = ((self.p2.x - self.p3.x) ** 2.0 + (self.p2.y - self.p3.y) ** 2.0) ** 0.5
        c: float = ((self.p3.x - self.p1.x) ** 2.0 + (self.p3.y - self.p1.y) ** 2.0) ** 0.5
        s: float = (a + b + c) / 2.0
        return (s * (s - a) * (s - b) * (s - c)) ** 0.5

    @override
    def perimeter(self) -> float:
        a: float = ((self.p1.x - self.p2.x) ** 2.0 + (self.p1.y - self.p2.y) ** 2.0) ** 0.5
        b: float = ((self.p2.x - self.p3.x) ** 2.0 + (self.p2.y - self.p3.y) ** 2.0) ** 0.5
        c: float = ((self.p3.x - self.p1.x) ** 2.0 + (self.p3.y - self.p1.y) ** 2.0) ** 0.5
        return a + b + c

    @override
    def draw(self) -> str:
        return "Triangle with vertices at specified points"

    @override
    def scale(self, factor: float) -> None:
        # Scale all points relative to p1
        origin: Point = self.p1
        self.p2 = Point(origin.x + (self.p2.x - origin.x) * factor, 
                        origin.y + (self.p2.y - origin.y) * factor)
        self.p3 = Point(origin.x + (self.p3.x - origin.x) * factor,
                        origin.y + (self.p3.y - origin.y) * factor)

