# Utility functions module

from types import Color

def format_area(area: float) -> str:
    return "Area: " + str(area)

def format_perimeter(perim: float) -> str:
    return "Perimeter: " + str(perim)

def color_to_string(color: Color) -> str:
    return color.name

def get_color_value(color: Color) -> int:
    return color.value
